const WF_ROT = {'chevron-left':90,'chevron-right':-90,'chevron-up':180,'chevron-down':0};
class WfIcon extends HTMLElement{
  connectedCallback(){ this.render(); }
  static get observedAttributes(){ return ['name']; }
  attributeChangedCallback(){ if(this.isConnected) this.render(); }
  render(){
    let n=this.getAttribute('name'); let d=WF_ICONS[n];
    let rot=WF_ROT[n]||0;
    // directional chevrons share the base "chevron-down" art, rotated
    if(!d && (n==='chevron-left'||n==='chevron-right'||n==='chevron-up')) d=WF_ICONS['chevron-down'];
    const t = rot ? ' style="transform:rotate('+rot+'deg)"' : '';
    this.innerHTML = d ? '<svg viewBox="'+d.vb+'" xmlns="http://www.w3.org/2000/svg"'+t+'>'+d.inner+'</svg>' : '';
  }
}
if(!customElements.get('wf-icon')) customElements.define('wf-icon', WfIcon);
